import type { AtomPosition, TimelineIconType } from './Timeline.types';
/** Возвращает тип Атома (кружочек с соединительной полосой)
 * active - маленький жёлтый
 * error - большой красный
 * current - большой жёлтый
 * inactive - маленький серый
 */
export const calcAtomType = (currentStepIndex: number, activeStepIndex: number, error?: boolean): TimelineIconType => {
	if (activeStepIndex > currentStepIndex) {
		return 'active';
	}

	if (currentStepIndex === activeStepIndex) {
		return error ? 'error' : 'current';
	}

	return 'inactive';
};

/** Возвращает позицию Атома (кружочек с соединительной полосой)
 * bottom - соединительная полоса только сверху
 * top - соединительная полоса только снизу
 * middle - соединительная полоса сверху и снизу
 */
export const calcStepPosition = (index: number, lastIndex?: number): AtomPosition => {
	if (index === lastIndex) {
		return 'bottom';
	}

	if (index === 0) {
		return 'top';
	}

	return 'middle';
};
